  import sailpoint.tools.Util;
  import sailpoint.object.QueryOptions;
  import sailpoint.object.Filter;
  import sailpoint.object.Identity;


  String userName = account.getStringAttribute("Empl Id") ;

  Map returnMap = new HashMap();

  if(Util.isNotNullOrEmpty(userName)){

      Filter identityNetworkLogonIDFilter = Filter.eq("samAccountName", userName.replaceAll("\"",""));

      List opUsersList = new ArrayList() ;

      QueryOptions ops = new QueryOptions();
      ops.addFilter(identityNetworkLogonIDFilter);

      List matchedIdentities = context.getObjects(Identity.class, ops);

      if(matchedIdentities!=null && matchedIdentities.size( )== 0){

        Filter identityNameFilter = Filter.eq("name", userName.replaceAll("\"",""));

        opUsersList = new ArrayList() ;

        ops = new QueryOptions();
        ops.addFilter(identityNameFilter);

        matchedIdentities = context.getObjects(Identity.class, ops);        
      } 

      if(matchedIdentities!=null && matchedIdentities.size() == 0 && Util.nullSafeCaseInsensitiveEq(application.getName(), "Star")){
        
        String adApplicationName = "AD-OKTUL" ;
        
        Filter linksApplicationNameFilter = Filter.eq("links.application.name", adApplicationName) ; 
        Filter linksDisplayNameFilter = Filter.contains("links.displayName", "SJMC\\"+userName) ;

        Filter finalFilter = Filter.and(linksApplicationNameFilter,linksDisplayNameFilter) ;

        ops = new QueryOptions();
        ops.addFilter(finalFilter);

        matchedIdentities = context.getObjects(Identity.class, ops); 
        
      }
      
      if(matchedIdentities!=null && matchedIdentities.size() == 0 && Util.nullSafeCaseInsensitiveEq(application.getName(), "Star-ALBIR")){
        
        String adApplicationName = "AD-DS" ;
        
        Filter linksApplicationNameFilter = Filter.eq("links.application.name", adApplicationName) ; 
        Filter linksDisplayNameFilter = Filter.contains("links.displayName", "ALBIR\\"+userName) ;

        Filter finalFilter = Filter.and(linksApplicationNameFilter,linksDisplayNameFilter) ;

        ops = new QueryOptions();
        ops.addFilter(finalFilter);

        matchedIdentities = context.getObjects(Identity.class, ops); 
        
      }
      
    if (matchedIdentities != null && matchedIdentities.size() == 1) {

      String matchedIdentityCubeName = matchedIdentities.get(0).getName() ;

      returnMap.put("identityName", matchedIdentityCubeName); 

    }  
  }

  return returnMap ;
